5	//! Branded commit message formatting infrastructure
6	//!
7	//! Provides shared brand retrieval and message formatting for all branded commits
8	//! (jjb: for Job Jockey, vvb: for VOK builds, etc.)
9	
10	use std::fs;
11	
12	/// Path to brand file containing vvbh_brand
13	pub const VVCC_BRAND_FILE_PATH: &str = ".vvk/vvbf_brand.json";
14	
15	/// Path to registry file for fallback brand lookup
16	pub const VVCC_REGISTRY_PATH: &str = "Tools/vok/vov_veiled/vovr_registry.json";
17	
18	/// JSON field name for brand in brand file
19	pub const VVCC_BRAND_FIELD: &str = "vvbf_brand";
20	
21	/// JSON field name for brands map in registry file
22	pub const VVCC_REGISTRY_BRANDS_FIELD: &str = "vovr_brands";
23	
24	/// Get brand for commit message versioning
25	///
26	/// Source logic:
27	/// 1. Try `.vvk/vvbf_brand.json` → if exists, use `vvbh_brand` (4 digits)
28	/// 2. If missing (Kit Forge) → read `Tools/vok/vov_veiled/vovr_registry.json`,
29	///    find max brand, get `git rev-parse --short HEAD`, format as `{brand}-{commit}`
30	pub fn vvcc_get_brand() -> String {
31	    // Try reading brand file
32	    if let Ok(brand_content) = fs::read_to_string(VVCC_BRAND_FILE_PATH) {
33	        if let Ok(brand_json) = serde_json::from_str::<serde_json::Value>(&brand_content) {
34	            if let Some(brand) = brand_json.get(VVCC_BRAND_FIELD) {
35	                if let Some(brand_str) = brand.as_str() {
36	                    return brand_str.to_string();
37	                }
38	            }
39	        }
40	    }
41	
42	    // Fallback: Kit Forge mode (read registry + git HEAD)
43	    let mut max_brand = 0u32;
44	    if let Ok(registry_content) = fs::read_to_string(VVCC_REGISTRY_PATH) {
45	        if let Ok(registry_json) = serde_json::from_str::<serde_json::Value>(&registry_content) {
46	            if let Some(brands) = registry_json.get(VVCC_REGISTRY_BRANDS_FIELD).and_then(|v| v.as_object()) {
47	                for key in brands.keys() {
48	                    if let Ok(num) = key.parse::<u32>() {
49	                        max_brand = max_brand.max(num);
50	                    }
51	                }
52	            }
53	        }
54	    }
55	
56	    // Get short commit hash
57	    let git_output = crate::vvce_git_command(&["rev-parse", "--short", "HEAD"])
58	        .output();
59	
60	    let commit_hash = if let Ok(output) = git_output {
61	        if output.status.success() {
62	            String::from_utf8_lossy(&output.stdout).trim().to_string()
63	        } else {
64	            "0000000".to_string()
65	        }
66	    } else {
67	        "0000000".to_string()
68	    };
69	
70	    format!("{:04}-{}", max_brand, commit_hash)
71	}
