155	/// Bash builtins and command-position keywords that name no external command —
156	/// never flagged. Keywords with control-flow semantics ([[, ]], the loop/branch
157	/// words) are handled structurally in the lexer; the rest live here so that a
158	/// builtin reaching classification (echo, printf, read, local, …) is cleared.
159	pub(crate) const ZRBTDRU_BUILTINS: &[&str] = &[
160	    ":", ".", "[", "[[", "]", "]]", "alias", "bg", "bind", "break", "builtin",
161	    "caller", "cd", "command", "compgen", "complete", "compopt", "continue",
162	    "coproc", "declare", "dirs", "disown", "echo", "enable", "eval", "exec",
163	    "exit", "export", "false", "fc", "fg", "getopts", "hash", "help", "history",
164	    "jobs", "kill", "let", "local", "logout", "mapfile", "popd", "printf",
165	    "pushd", "pwd", "read", "readarray", "readonly", "return", "set", "shift",
166	    "shopt", "source", "suspend", "test", "times", "trap", "true", "type",
167	    "typeset", "ulimit", "umask", "unalias", "unset", "wait",
168	];
