186	    zrbtdru_Eviction { command: "ls", replacement: "glob expansion (for f in dir/*)" },
187	    zrbtdru_Eviction { command: "sha256sum", replacement: "openssl dgst -sha256 -r" },
188	    zrbtdru_Eviction { command: "shasum", replacement: "openssl dgst -sha256 -r" },
189	    zrbtdru_Eviction { command: "tr", replacement: "${var//old/new} parameter expansion" },
