202	/// A single command-discipline violation: where it is and why it failed.
203	#[derive(Clone, Debug)]
204	pub(crate) struct zrbtdru_Finding {
205	    pub(crate) file: String,
206	    pub(crate) line: usize,
207	    pub(crate) command: String,
208	    pub(crate) detail: String,
