211	// ── Lexer ───────────────────────────────────────────────────
212	
213	/// Read one shell word starting at `*i`, advancing `*i` past it and `*line`
214	/// over any embedded newlines. Quoted segments and `${...}` parameter
215	/// expansions are consumed as part of the word; an embedded `$(` command
216	/// substitution STOPS the word so the caller's lexer scans the substituted
217	/// command at its own command position.
218	pub(crate) fn zrbtdru_read_word(chars: &[char], i: &mut usize, line: &mut usize) -> String {
219	    let n = chars.len();
220	    let mut word = String::new();
221	    while *i < n {
222	        let c = chars[*i];
223	        match c {
224	            ' ' | '\t' | '\r' | '\n' => break,
225	            ';' | '|' | '&' | '<' | '>' | '(' | ')' | '`' | '#' => break,
226	            '\'' => {
227	                word.push(c);
228	                *i += 1;
229	                while *i < n && chars[*i] != '\'' {
230	                    if chars[*i] == '\n' {
231	                        *line += 1;
232	                    }
233	                    word.push(chars[*i]);
234	                    *i += 1;
235	                }
236	                if *i < n {
237	                    word.push(chars[*i]);
238	                    *i += 1;
239	                }
240	            }
241	            '"' => {
242	                word.push(c);
243	                *i += 1;
244	                while *i < n && chars[*i] != '"' {
245	                    if chars[*i] == '\\' && *i + 1 < n {
246	                        word.push(chars[*i]);
247	                        word.push(chars[*i + 1]);
248	                        *i += 2;
249	                        continue;
250	                    }
251	                    if chars[*i] == '\n' {
252	                        *line += 1;
253	                    }
254	                    word.push(chars[*i]);

400	        let c = chars[i];
401	
402	        if c == '\n' {
403	            i += 1;
404	            line += 1;
405	            cmd_pos = true;
406	            if let Some(delim) = pending_heredoc.take() {
407	                loop {
408	                    let start = i;
409	                    while i < n && chars[i] != '\n' {
410	                        i += 1;
411	                    }
412	                    let body: String = chars[start..i].iter().collect();
413	                    let had_nl = i < n;
414	                    if had_nl {
415	                        i += 1;
416	                        line += 1;
417	                    }
418	                    if body.trim() == delim {
419	                        break;
420	                    }
421	                    if !had_nl {
422	                        break;
423	                    }
424	                }
425	            }
426	            continue;
427	        }
428	        if c == ' ' || c == '\t' || c == '\r' {
429	            i += 1;
430	            continue;
431	        }
432	        if c == '\\' && i + 1 < n && chars[i + 1] == '\n' {
433	            i += 2;
434	            line += 1;
435	            continue;
436	        }
437	        if c == '#' {
438	            while i < n && chars[i] != '\n' {
439	                i += 1;
440	            }
441	            continue;
442	        }
443	        if c == ';' {
444	            i += 1;
445	            if i < n && chars[i] == ';' {
446	                i += 1;
447	                // `;;` ends a case branch — the next token opens a new pattern.
448	                if let Some(top) = case_stack.last_mut() {
449	                    *top = 1;
450	                }
451	                cmd_pos = false;
452	                continue;
453	            }
454	            if !in_dbracket {
455	                cmd_pos = true;
456	            }
457	            continue;
458	        }
459	        if c == '|' {
460	            i += 1;
461	            if i < n && chars[i] == '|' {
462	                i += 1;
463	            }
464	            // Within a case pattern `|` is alternation, not a pipe.
465	            if case_stack.last() == Some(&1) {
466	                continue;
467	            }
468	            if !in_dbracket {
469	                cmd_pos = true;
470	            }
471	            continue;
472	        }
473	        if c == '&' {
474	            if i + 1 < n && chars[i + 1] == '>' {
475	                i += 2;
476	                if i < n && chars[i] == '>' {
477	                    i += 1;
478	                }
479	                cmd_pos = false;
480	                continue;
481	            }
482	            i += 1;
483	            if i < n && chars[i] == '&' {
484	                i += 1;
485	            }
486	            if !in_dbracket {
487	                cmd_pos = true;
488	            }
489	            continue;
490	        }
491	        if c == '<' {
492	            if i + 1 < n && chars[i + 1] == '<' {
493	                if i + 2 < n && chars[i + 2] == '<' {
494	                    i += 3;
495	                    cmd_pos = false;
496	                    continue;
497	                }
498	                i += 2;
499	                if i < n && chars[i] == '-' {

600	                    zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
601	                    cmd_pos = false;
602	                    continue;
603	                }
604	                i += 2;
605	                paren_depth += 1;
606	                cmd_pos = true;
607	                continue;
608	            }
609	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
610	            cmd_pos = false;
611	            continue;
612	        }
613	        if c == '{' {
614	            if i + 1 < n && (chars[i + 1] == ' ' || chars[i + 1] == '\t' || chars[i + 1] == '\n') {
615	                i += 1;
616	                cmd_pos = true;
617	                continue;
618	            }
619	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
620	            cmd_pos = false;
621	            continue;
622	        }
623	        if c == '}' {
624	            i += 1;
625	            continue;
626	        }
627	
628	        let word_line = line;
629	        let word = zrbtdru_read_word(&chars, &mut i, &mut line);
630	        if word.is_empty() {
631	            i += 1;
632	            continue;
633	        }
634	        if word == "[[" {
635	            if cmd_pos {
636	                in_dbracket = true;
637	            }
638	            cmd_pos = false;
639	            continue;
640	        }
641	        if word == "]]" {
642	            in_dbracket = false;
643	            cmd_pos = false;
644	            continue;
645	        }
646	        if in_dbracket {
647	            continue;
648	        }
649	        // case…esac structure — tracked regardless of command position so that
650	        // branch patterns (which sit at command position) are not mistaken for
651	        // commands.
652	        if word == "case" {
653	            case_stack.push(0);
654	            cmd_pos = false;
655	            continue;
656	        }
657	        if word == "esac" {
658	            case_stack.pop();
659	            cmd_pos = false;
660	            continue;
661	        }
662	        if word == "in" && case_stack.last() == Some(&0) {
663	            if let Some(top) = case_stack.last_mut() {
664	                *top = 1;
665	            }
666	            cmd_pos = false;
667	            continue;
668	        }
669	        if case_stack.last() == Some(&1) {
670	            // Matching a case pattern — suppress; the pattern is not a command.
671	            cmd_pos = false;
672	            continue;
673	        }
674	        if !cmd_pos {
675	            continue;
676	        }
677	        if zrbtdru_is_assignment(&word) {
678	            // `NAME=( … )` array literal — the elements are data, not commands.
679	            let mut j = i;
680	            while j < n && (chars[j] == ' ' || chars[j] == '\t') {
681	                j += 1;
682	            }
683	            if j < n && chars[j] == '(' {
684	                i = j + 1;
685	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 1);
686	            }
687	            continue;
688	        }
689	        match zrbtdru_keyword_kind(&word) {
690	            Some(true) => continue,
691	            Some(false) => {
692	                cmd_pos = false;
693	                continue;
694	            }
695	            None => {}
696	        }
697	        out.push((word_line, word));
698	        cmd_pos = false;
699	    }

700	    out
701	}
