786	/// True when `command` names an external command in the corpus's surface — a
787	/// static token that is neither a bash builtin nor a locally-defined function.
788	/// This is the classification-independent inventory predicate: it admits the
789	/// union of allowed externals (floor / declared / gcb-extra / tolerated
790	/// evictions) AND violations. Dynamic tokens (expansion or quote) cannot be
791	/// statically named and are excluded.
792	fn zrbtdru_is_external(command: &str, locals: &BTreeSet<String>) -> bool {
793	    if command.is_empty()
794	        || command.contains('$')
795	        || command.contains('`')
796	        || command.contains('"')
797	        || command.contains('\'')
798	    {
799	        return false;

800	    }
801	    let base = command.rsplit('/').next().unwrap_or(command);
802	    !ZRBTDRU_BUILTINS.contains(&base)
803	        && !locals.contains(command)
804	        && !locals.contains(base)
805	}
