807	/// One domain scan: violations, plus the full external-command inventory (base
808	/// command names, deduplicated and sorted) — the empirical basis for curating
809	/// an allowlist.
810	struct zrbtdru_ScanResult {
811	    findings: Vec<zrbtdru_Finding>,
812	    inventory: BTreeSet<String>,
813	}
814	
815	// ── Corpus walk and scan ────────────────────────────────────
816	
817	/// Recursively collect every `*.sh` file under `dir` into `out`, skipping any
818	/// subdirectory whose basename begins with one of `excluded_prefixes`.
819	fn zrbtdru_walk_sh(dir: &Path, excluded_prefixes: &[&str], out: &mut Vec<PathBuf>) {
820	    let entries = match std::fs::read_dir(dir) {
821	        Ok(e) => e,
822	        Err(_) => return,
823	    };
824	    for entry in entries.flatten() {
825	        let path = entry.path();
826	        if path.is_dir() {
827	            let excluded = path
828	                .file_name()
829	                .and_then(|s| s.to_str())
830	                .map(|name| {
831	                    excluded_prefixes
832	                        .iter()
833	                        .any(|prefix| name.starts_with(prefix))
834	                })
835	                .unwrap_or(false);
836	            if excluded {
837	                continue;
838	            }
839	            zrbtdru_walk_sh(&path, excluded_prefixes, out);
840	        } else if path.extension().and_then(|e| e.to_str()) == Some(ZRBTDRU_SH_EXT) {
841	            out.push(path);
842	        }
843	    }
844	}
