857	/// Walk the corpus, collect functions across all of it, then scan the files
858	/// belonging to `domain`, returning every finding (sorted by file and line)
859	/// plus the domain's external-command inventory.
860	fn zrbtdru_scan_domain(tools: &Path, domain: zrbtdru_Domain) -> Result<zrbtdru_ScanResult, String> {
861	    // Pass 1 — function-visibility universe. Walk every kit so cross-kit and
862	    // sourced function names resolve (e.g. rbk's Windows handbook sources jjk's
863	    // zipper); only dead ABANDONED code stays invisible.
864	    let mut universe_files: Vec<PathBuf> = Vec::new();
865	    zrbtdru_walk_sh(tools, ZRBTDRU_UNIVERSE_EXCLUDED_DIR_PREFIXES, &mut universe_files);
866	    universe_files.sort();
867	
868	    let mut locals: BTreeSet<String> = BTreeSet::new();
869	    for f in &universe_files {
870	        let src = std::fs::read_to_string(f)
871	            .map_err(|e| format!("read {} failed: {}", f.display(), e))?;
872	        zrbtdru_collect_functions(&src, &mut locals);
873	    }
874	
875	    // Pass 2 — lint target. Only the release kit roots, minus dead/not-yet-live.
876	    let mut lint_files: Vec<PathBuf> = Vec::new();
877	    for kit in ZRBTDRU_KIT_ROOTS {
878	        zrbtdru_walk_sh(&tools.join(kit), ZRBTDRU_LINT_EXCLUDED_DIR_PREFIXES, &mut lint_files);
879	    }
880	    lint_files.sort();
881	
882	    let root = tools.parent().unwrap_or(tools);
883	    let mut findings: Vec<zrbtdru_Finding> = Vec::new();
884	    let mut inventory: BTreeSet<String> = BTreeSet::new();
885	    for path in &lint_files {
886	        let is_gcb = zrbtdru_is_gcb(path);
887	        let in_domain = match domain {
888	            zrbtdru_Domain::Kit => !is_gcb,
